1046	feed it to a scheme-gluing machine we must re-express each piece as a morphism in
1047	the category of schemes: the charts \(U^I\), the principal-open overlaps
1048	\(U^I_J\), their inclusions, and the transitions \(\theta_{I,J}\) all become
1049	schemes and scheme morphisms by applying the contravariant functor \(\Spec\).
1050	The lemmas of this section record those translations together with the two
1051	genuinely geometric facts needed to assemble a glue datum: that each inclusion
1052	\(U^I_J \hookrightarrow U^I\) is an open immersion, and that the fibre product of
1053	two principal opens of \(\Spec A\) is again a principal open. They are
1054	project-internal bridge results with no external source beyond the gluing
1055	construction of \cref{def:gr_glued_scheme}.
1056	
1057	\subsection*{Mathlib inputs for the scheme-level layer}
1058	
1059	\begin{lemma}
1060	[\(\Spec\) of an away-localisation is an open immersion]
1061	  \label{lem:mathlib_specMap_localizationAway_isOpenImmersion}
1062	  \lean{AlgebraicGeometry.Scheme.isOpenImmersion_SpecMap_localizationAway}
1063	  \mathlibok
1064	  \textit{Provided by Mathlib.}
1065	  Let \(R\) be a commutative ring and \(f \in R\). The morphism
1066	  \(\Spec R[1/f] \to \Spec R\) induced by the structure map \(R \to R[1/f]\) of
1067	  the away-localisation is an open immersion (onto the basic open
1068	  \(D(f) \subseteq \Spec R\)).
1069	\end{lemma}
1070	
1071	\begin{lemma}
1072	[Fibre product of two affine spectra is \(\Spec\) of the tensor product]
1073	  \label{lem:mathlib_pullbackSpecIso}
1074	  \lean{AlgebraicGeometry.pullbackSpecIso}
1075	  \mathlibok
1076	  \textit{Provided by Mathlib.}
1077	  Let \(R\) be a commutative ring and \(S\), \(T\) two \(R\)-algebras. The fibre
1078	  product of \(\Spec S \to \Spec R \leftarrow \Spec T\) is canonically isomorphic
1079	  to the spectrum of the tensor product:
1080	  \[
1081	    \Spec S \times_{\Spec R} \Spec T \;\cong\; \Spec\bigl(S \otimes_R T\bigr).
1082	  \]
1083	\end{lemma}
1084	
1085	\begin{lemma}
1086	[An away-localisation of a tensor product is a double away-localisation]
1087	  \label{lem:mathlib_isLocalization_away_mul}
1088	  \lean{IsLocalization.Away.mul'}
1089	  \mathlibok
1090	  \textit{Provided by Mathlib.}
1091	  Let \(R\) be a commutative ring, \(x, y \in R\), and \(R[1/x]\) the localisation
1092	  away from \(x\). Then \(R[1/x] \otimes_R R[1/y]\) is a localisation of \(R\)
1093	  away from \(x y\); equivalently it realises \(R[1/(xy)]\).
1094	\end{lemma}
1095	
1096	\begin{lemma}
1097	[Two away-localisations of the same element are canonically isomorphic]
1098	  \label{lem:mathlib_isLocalization_algEquiv}
1099	  \lean{IsLocalization.algEquiv}
1100	  \mathlibok
1101	  \textit{Provided by Mathlib.}
1102	  Let \(R\) be a commutative ring and \(M \subseteq R\) a submonoid. Any two
1103	  localisations of \(R\) at \(M\) are uniquely \(R\)-algebra isomorphic; in
1104	  particular, given two rings each presented as \(R[1/x]\) there is a canonical
1105	  \(R\)-algebra isomorphism between them.
1106	\end{lemma}
1107	
1108	\subsection*{Charts, overlaps, and inclusions as schemes}
1109	
1110	\begin{theorem}
1111	
1112	\leanok
1113	[The diagonal minor is the unit]
1114	  \label{lem:gr_minorDet_self}
1115	  \lean{AlgebraicGeometry.Grassmannian.minorDet_self}
1116	  \uses{def:gr_minor_det, lem:gr_universalMatrix_submatrix_self}
1117	  For every size-\(d\) subset \(I\), the \(I\)-minor determinant of the universal
1118	  matrix \(X^I\) is the unit of the chart ring:
1119	  \[
1120	    P^I_I \;=\; 1 \;\in\; R^I.
1121	  \]
1122	\end{theorem}
1123	\begin{proof}
1124	  \uses{def:gr_minor_det, lem:gr_universalMatrix_submatrix_self}
1125	  \leanok
1126	  The \(I\)-minor \(X^I_I\) is the \(d \times d\) identity
1127	  (\cref{lem:gr_universalMatrix_submatrix_self}), and \(\det(1_{d\times d}) = 1\).
1128	  Proved directly in Lean.
1129	\end{proof}
1130	
1131	\begin{definition}
1132	
1133	\leanok
1134	[The overlap scheme \(U^I_J\)]
1135	  \label{def:gr_chart_overlap}
1136	  \lean{AlgebraicGeometry.Grassmannian.chartOverlap}
1137	  \uses{def:gr_minor_det, def:gr_affine_chart}
1138	  The principal-open overlap, as a scheme, is the affine spectrum of the
1139	  away-localisation of the chart ring \(R^I\) (\cref{def:gr_affine_chart}) at the
1140	  minor determinant \(P^I_J\) (\cref{def:gr_minor_det}):
1141	  \[
1142	    U^I_J \;:=\; \Spec R^I[1/P^I_J].
1143	  \]
1144	  It is the \(V\)-object of the Grassmannian glue datum.
1145	\end{definition}
1146	
1147	\begin{definition}
1148	
1149	\leanok
1150	[The overlap inclusion \(U^I_J \to U^I\)]
1151	  \label{def:gr_chart_incl}
1152	  \lean{AlgebraicGeometry.Grassmannian.chartIncl}
1153	  \uses{def:gr_chart_overlap, def:gr_affine_chart}
1154	  The canonical inclusion of the overlap into the chart is the \(\Spec\) of the
1155	  structure map \(R^I \to R^I[1/P^I_J]\):
1156	  \[
1157	    U^I_J \;=\; \Spec R^I[1/P^I_J] \longrightarrow \Spec R^I \;=\; U^I .
1158	  \]
1159	  It is the \(f\)-field of the Grassmannian glue datum.
1160	\end{definition}
1161	
1162	\begin{lemma}
1163	
1164	\leanok
1165	[The overlap inclusion is an open immersion]
1166	  \label{lem:gr_chartIncl_isOpenImmersion}
1167	  \lean{AlgebraicGeometry.Grassmannian.chartIncl_isOpenImmersion}
1168	  \uses{def:gr_chart_incl, lem:mathlib_specMap_localizationAway_isOpenImmersion}
1169	  The inclusion \(U^I_J \hookrightarrow U^I\) (\cref{def:gr_chart_incl}) is an
1170	  open immersion, identifying \(U^I_J\) with the basic open \(D(P^I_J)\) of
1171	  \(U^I\).
1172	\end{lemma}
1173	\begin{proof}
1174	  \uses{def:gr_chart_incl, lem:mathlib_specMap_localizationAway_isOpenImmersion}
1175	  \leanok
1176	  This is exactly the away-localisation open-immersion fact
1177	  (\cref{lem:mathlib_specMap_localizationAway_isOpenImmersion}) applied to
1178	  \(f = P^I_J\). Proved directly in Lean.
1179	\end{proof}
1180	
1181	\begin{lemma}
1182	
1183	\leanok
1184	[The self-overlap inclusion is an isomorphism]
1185	  \label{lem:gr_chartIncl_self_isIso}
1186	  \lean{AlgebraicGeometry.Grassmannian.chartIncl_self_isIso}
1187	  \uses{def:gr_chart_incl, lem:gr_minorDet_self}
1188	  For every \(I\), the self-inclusion \(U^I_I \to U^I\) (\cref{def:gr_chart_incl})
1189	  is an isomorphism. This is the \(f_{\mathrm{id}}\)-field of the glue datum.
1190	\end{lemma}
1191	\begin{proof}
1192	  \uses{def:gr_chart_incl, lem:gr_minorDet_self}
1193	  \leanok
1194	  Since \(P^I_I = 1\) is a unit (\cref{lem:gr_minorDet_self}), the structure map
1195	  \(R^I \to R^I[1/P^I_I]\) is the localisation at a unit, hence an isomorphism of
1196	  rings; applying \(\Spec\) gives an isomorphism of schemes. Proved directly in
1197	  Lean.
1198	\end{proof}
1199	
1200	\begin{definition}
1201	
1202	\leanok
1203	[The scheme-level transition \(U^I_J \to U^J_I\)]
1204	  \label{def:gr_chart_transition}
1205	  \lean{AlgebraicGeometry.Grassmannian.chartTransition}
1206	  \uses{def:gr_transition, def:gr_chart_overlap}
1207	  The scheme-level transition is the \(\Spec\) of the ring transition map
1208	  \(\theta_{I,J} : R^J[1/P^J_I] \to R^I[1/P^I_J]\) (\cref{def:gr_transition}):
1209	  \[
1210	    U^I_J \;=\; \Spec R^I[1/P^I_J] \longrightarrow \Spec R^J[1/P^J_I] \;=\; U^J_I .
1211	  \]
1212	  It is the \(t\)-field of the Grassmannian glue datum.
1213	\end{definition}
1214	
1215	\begin{lemma}
1216	
1217	\leanok
1218	[The self-transition is the identity]
1219	  \label{lem:gr_chartTransition_self}
1220	  \lean{AlgebraicGeometry.Grassmannian.chartTransition_self}
1221	  \uses{def:gr_chart_transition, lem:gr_transition_self}
1222	  For every \(I\), the scheme-level self-transition
1223	  \(U^I_I \to U^I_I\) (\cref{def:gr_chart_transition}) is the identity. This is
1224	  the \(t_{\mathrm{id}}\)-field of the glue datum.
1225	\end{lemma}
1226	\begin{proof}
1227	  \uses{def:gr_chart_transition, lem:gr_transition_self}
1228	  \leanok
1229	  By \cref{lem:gr_transition_self} the ring map \(\theta_{I,I}\) is the identity,
1230	  and \(\Spec\) sends the identity ring map to the identity morphism. Proved
1231	  directly in Lean.
1232	\end{proof}
1233	
1234	\subsection*{The away-localisation pullback isomorphism}
1235	
1236	\begin{definition}
1237	
1238	\leanok
1239	[Pullback of two principal opens of \(\Spec A\)]
1240	  \label{def:gr_away_pullback_iso}
1241	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso}
1242	  \uses{lem:mathlib_pullbackSpecIso, lem:mathlib_isLocalization_away_mul, lem:mathlib_isLocalization_algEquiv}
1243	  Let \(A\) be a commutative ring and \(x, y \in A\). The fibre product of the two
1244	  basic-open inclusions \(\Spec A[1/x] \to \Spec A \leftarrow \Spec A[1/y]\) is
1245	  canonically isomorphic to the spectrum of the doubly-inverted localisation:
1246	  \[
1247	    \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1248	      \;\cong\; \Spec A[1/(xy)].
1249	  \]
1250	  The isomorphism is the composite of the tensor-product identification of the
1251	  pullback (\cref{lem:mathlib_pullbackSpecIso}) with the \(\Spec\) of the
1252	  localisation isomorphism
1253	  \(A[1/x] \otimes_A A[1/y] \cong A[1/(xy)]\)
1254	  (\cref{lem:mathlib_isLocalization_away_mul},
1255	  \cref{lem:mathlib_isLocalization_algEquiv}). It is stated over a general base
1256	  ring \(A\) so that it may be instantiated at the triple-overlap rings of the
1257	  Grassmannian glue datum.
1258	\end{definition}
1259	
1260	\begin{lemma}
1261	
1262	\leanok
1263	[Left leg of the pullback isomorphism]
1264	  \label{lem:gr_awayPullbackIso_inv_fst}
1265	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_fst}
1266	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1267	  Under the identification of \cref{def:gr_away_pullback_iso}, the first
1268	  projection of the pullback corresponds to the left away-inclusion: the
1269	  composite
1270	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1271	    \xrightarrow{\mathrm{pr}_1} \Spec A[1/x]\)
1272	  equals \(\Spec\) of the inclusion \(\iota^{\mathrm{L}}_{x,y}\)
1273	  (\cref{def:gr_away_incl_left}).
1274	\end{lemma}
1275	\begin{proof}
1276	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_left}
1277	  \leanok
1278	  The pullback-projection compatibility of the tensor-product identification
1279	  sends \(\mathrm{pr}_1\) to the left tensor inclusion, which under the
1280	  localisation isomorphism is the structure map \(A[1/x] \to A[1/(xy)]\), i.e.\
1281	  \(\iota^{\mathrm{L}}_{x,y}\); the verification is the universal property of the
1282	  away-localisation. Proved directly in Lean.
1283	\end{proof}
1284	
1285	\begin{lemma}
1286	
1287	\leanok
1288	[Right leg of the pullback isomorphism]
1289	  \label{lem:gr_awayPullbackIso_inv_snd}
1290	  \lean{AlgebraicGeometry.Grassmannian.awayPullbackIso_inv_snd}
1291	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1292	  Symmetrically, the second projection of the pullback corresponds to the right
1293	  away-inclusion: the composite
1294	  \(\Spec A[1/(xy)] \to \Spec A[1/x] \times_{\Spec A} \Spec A[1/y]
1295	    \xrightarrow{\mathrm{pr}_2} \Spec A[1/y]\)
1296	  equals \(\Spec\) of \(\iota^{\mathrm{R}}_{x,y}\)
1297	  (\cref{def:gr_away_incl_right}).
1298	\end{lemma}
1299	\begin{proof}
1300	  \uses{def:gr_away_pullback_iso, def:gr_away_incl_right}
1301	  \leanok
1302	  As in \cref{lem:gr_awayPullbackIso_inv_fst}, with the right tensor inclusion in
1303	  place of the left. Proved directly in Lean.
1304	\end{proof}
1305	
1306	\begin{definition}
1307	
1308	\leanok
1309	[Order-swap isomorphism \(A[1/(xy)] \cong A[1/(yx)]\)]
1310	  \label{def:gr_away_mul_comm_equiv}
1311	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv}
1312	  \uses{lem:mathlib_isLocalization_algEquiv}
1313	  For \(x, y \in A\), the canonical ring isomorphism
1314	  \[
1315	    A[1/(xy)] \;\cong\; A[1/(yx)]
1316	  \]
1317	  identifying the two away-localisations, which agree because \(xy\) and \(yx\)
1318	  generate the same submonoid of \(A\)
1319	  (\cref{lem:mathlib_isLocalization_algEquiv}). It is inserted into the
1320	  triple-cocycle field of the glue datum to reconcile the opposite product
1321	  orders produced by the two pullback isomorphisms.
1322	\end{definition}
1323	
1324	\begin{lemma}
1325	
1326	\leanok
1327	[The order-swap lies over the base ring]
1328	  \label{lem:gr_awayMulCommEquiv_comp_algebraMap}
1329	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_algebraMap}
1330	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1331	  The order-swap isomorphism (\cref{def:gr_away_mul_comm_equiv}) intertwines the
1332	  two structure maps: for \(x, y \in A\),
1333	  \[
1334	    \mathrm{swap}_{x,y} \circ \bigl(A \to A[1/(xy)]\bigr)
1335	      \;=\; \bigl(A \to A[1/(yx)]\bigr).
1336	  \]
1337	\end{lemma}
1338	\begin{proof}
1339	  \uses{def:gr_away_mul_comm_equiv, lem:mathlib_isLocalization_algEquiv}
1340	  \leanok
1341	  Both \(A[1/(xy)]\) and \(A[1/(yx)]\) are localisations of \(A\) at the same
1342	  submonoid (\(xy\) and \(yx\) generate it), and the canonical comparison map
1343	  between two such localisations is an \(A\)-algebra isomorphism
1344	  (\cref{lem:mathlib_isLocalization_algEquiv}); an \(A\)-algebra map commutes with
1345	  the structure maps. Proved directly in Lean.
1346	\end{proof}
1347	
1348	\begin{lemma}
1349	
1350	\leanok
1351	[The order-swap absorbs the left inclusion into the right one]
1352	  \label{lem:gr_awayMulCommEquiv_comp_awayInclLeft}
1353	  \lean{AlgebraicGeometry.Grassmannian.awayMulCommEquiv_comp_awayInclLeft}
1354	  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
1355	  For \(x, y \in A\), pre-composing the order-swap isomorphism
1356	  \(\mathrm{swap}_{x,y} : A[1/(xy)] \cong A[1/(yx)]\)
1357	  (\cref{def:gr_away_mul_comm_equiv}) with the left away-inclusion
1358	  \(\iota^{\mathrm{L}}_{x,y} : A[1/x] \to A[1/(xy)]\)
1359	  (\cref{def:gr_away_incl_left}) yields the right away-inclusion of the swapped
1360	  pair:
1361	  \[
1362	    \mathrm{swap}_{x,y} \circ \iota^{\mathrm{L}}_{x,y}
1363	      \;=\; \iota^{\mathrm{R}}_{y,x}
1364	      \;:\; A[1/x] \longrightarrow A[1/(yx)] ,
1365	  \]
1366	  where \(\iota^{\mathrm{R}}_{y,x} : A[1/x] \to A[1/(yx)]\) is the right
1367	  away-inclusion (\cref{def:gr_away_incl_right}) for the pair \((y, x)\). This is
1368	  the order-swap coherence used to rotate the triple-overlap transitions.
1369	\end{lemma}
1370	\begin{proof}
1371	  \uses{def:gr_away_mul_comm_equiv, def:gr_away_incl_left, def:gr_away_incl_right, lem:gr_awayInclLeft_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:gr_awayInclRight_comp_algebraMap, lem:mathlib_away_lift}
1372	  \leanok
1373	  Both sides are ring maps out of the away-localisation \(A[1/x]\), so by the
1374	  universal property of the localisation -- the uniqueness of an extension along
1375	  the structure map \(A \to A[1/x]\) (\cref{lem:mathlib_away_lift}) -- it suffices
1376	  to check equality after pre-composing with that structure map, i.e.\ on the base
1377	  ring \(A\). There all three away-maps collapse to structure maps into
1378	  \(A[1/(yx)]\): the left inclusion by
1379	  \cref{lem:gr_awayInclLeft_comp_algebraMap}, the order-swap by
1380	  \cref{lem:gr_awayMulCommEquiv_comp_algebraMap}, and the right inclusion by
1381	  \cref{lem:gr_awayInclRight_comp_algebraMap}. The two composites therefore agree
1382	  on \(A\), hence everywhere. Proved directly in Lean.
1383	\end{proof}
1384	
1385	\subsection*{The triple-overlap glue field \(t'\)}
1386	
1387	The scheme-gluing machine requires, beyond the pairwise transitions \(t_{I,J}\), a
1388	\emph{triple-overlap} field \(t'\) on the relevant fibre products, together with
1389	its compatibility \(t_{\mathrm{fac}}\) with the chart projections. We record both
1390	as the next layer of bridge results; their cocycle coherence is the residual
1391	obligation discharged in \cref{def:gr_glued_scheme}.
1392	
1393	\begin{definition}
1394	
1395	\leanok
1396	[The triple-overlap transition \(t'\)]
1397	  \label{def:gr_chart_transition'}
1398	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'}
1399	  \uses{def:gr_away_pullback_iso, def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv}
1400	  The \(t'\)-field of the Grassmannian glue datum is the morphism of schemes
1401	  \[
1402	    t'_{I,J,K} : U^I_J \times_{U^I} U^I_K \longrightarrow U^J_K \times_{U^J} U^J_I ,
1403	  \]
1404	  defined as the composite
1405	  \[
1406	    U^I_J \times_{U^I} U^I_K
1407	      \xrightarrow{\ \sim\ } \Spec S_I
1408	      \xrightarrow{\ \Spec \Theta_{I,J}\ } \Spec S_J
1409	      \xrightarrow{\ \Spec \mathrm{swap}\ } \Spec R^J[1/(P^J_K P^J_I)]
1410	      \xrightarrow{\ \sim\ } U^J_K \times_{U^J} U^J_I ,
1411	  \]
1412	  where the first and last arrows are the pullback identifications of
1413	  \cref{def:gr_away_pullback_iso} -- the source one for the pair \((P^I_J, P^I_K)\)
1414	  over \(R^I\), and the target one (taken inverse) for the pair \((P^J_K, P^J_I)\)
1415	  over \(R^J\) -- the middle arrow is the \(\Spec\) of the localised
1416	  triple-overlap transition \(\Theta_{I,J} : S_J \to S_I\)
1417	  (\cref{def:gr_cocycle_theta_ij}), and \(\mathrm{swap}\) is the \(\Spec\) of the
1418	  order-swap isomorphism \(R^J[1/(P^J_K P^J_I)] \cong S_J = R^J[1/(P^J_I P^J_K)]\)
1419	  (\cref{def:gr_away_mul_comm_equiv}). The order-swap is inserted precisely to
1420	  reconcile the product order \(P^J_K P^J_I\) carried by the target pullback
1421	  identification with the order \(P^J_I P^J_K\) of the codomain \(S_J\) of
1422	  \(\Theta_{I,J}\).
1423	\end{definition}
1424	
1425	\begin{lemma}
1426	
1427	\leanok
1428	[The \(t'\) ring identity]
1429	  \label{lem:gr_chartTransition'_ringIdentity}
1430	  \lean{AlgebraicGeometry.Grassmannian.chartTransition'_ringIdentity}
1431	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1432	  Over the triple-overlap rings, the localised transition \(\Theta_{I,J}\)
1433	  (\cref{def:gr_cocycle_theta_ij}) pre-composed with the order-swap and the right
1434	  inclusion equals the left inclusion post-composed with the plain transition
1435	  \(\theta_{I,J}\), as ring homomorphisms \(R^J[1/P^J_I] \to S_I\):
1436	  \[
1437	    \Theta_{I,J} \circ \mathrm{swap} \circ \iota^{\mathrm{R}}_{P^J_K, P^J_I}
1438	      \;=\; \iota^{\mathrm{L}}_{P^I_J, P^I_K} \circ \theta_{I,J} .
1439	  \]
1440	\end{lemma}
1441	\begin{proof}
1442	  \uses{def:gr_cocycle_theta_ij, def:gr_away_mul_comm_equiv, def:gr_away_incl_right, def:gr_away_incl_left, def:gr_transition, lem:gr_awayInclRight_comp_algebraMap, lem:gr_awayMulCommEquiv_comp_algebraMap, lem:mathlib_away_lift}
1443	  \leanok
1444	  Both sides are ring maps out of the away-localisation \(R^J[1/P^J_I]\), so by the
1445	  universal property of the localisation (\cref{lem:mathlib_away_lift}) it suffices
1446	  to check equality after pre-composing with the structure map
1447	  \(R^J \to R^J[1/P^J_I]\), i.e.\ on the chart ring \(R^J\). There the right
1448	  inclusion and the order-swap collapse to structure maps
1449	  (\cref{lem:gr_awayInclRight_comp_algebraMap},
1450	  \cref{lem:gr_awayMulCommEquiv_comp_algebraMap}), and the lift defining
1451	  \(\Theta_{I,J}\) (\cref{def:gr_cocycle_theta_ij}) unwinds to
1452	  \(\iota^{\mathrm{L}} \circ \tilde\theta_{I,J}\)
