1711	\section{Separatedness}
1712	\label{sec:gr_separated}
1713	
1714	The surjectivity of the restricted-diagonal comorphism is the ring-theoretic
1715	heart of separatedness. We isolate it through the following sequence of
1716	helper results before stating the keystone lemma.
1717	
1718	\begin{lemma}
1719	
1720	\leanok
1721	[Two-sided inverse identity \(\tilde\theta_{I,J}(P^J_I)\,P^I_J = 1\)]
1722	  \label{lem:gr_transitionPreMap_minorDet_swap_mul}
1723	  \lean{AlgebraicGeometry.Grassmannian.transitionPreMap_minorDet_swap_mul}
1724	  \uses{lem:gr_universalMatrix_map_transitionPreMap, lem:gr_transition_pre_unit, lem:gr_transitionPreMap_minorDet}
1725	  In \(R^I_J = \mathbb{Z}[X^I, 1/P^I_J]\), the pre-localisation transition hom
1726	  \(\tilde\theta_{I,J}\) (\cref{def:gr_transition_pre}) satisfies the explicit
1727	  two-sided inverse identity
1728	  \[
1729	    \tilde\theta_{I,J}\bigl(P^J_I\bigr) \cdot P^I_J \;=\; 1 .
1730	  \]
1731	  This refines the unit assertion of \cref{lem:gr_transition_pre_unit} to a named
1732	  inverse: \(\tilde\theta_{I,J}(P^J_I)\) is the explicit inverse of \(P^I_J\) in
1733	  \(R^I_J\).
1734	\end{lemma}
1735	\begin{proof}
1736	  \uses{lem:gr_universalMatrix_map_transitionPreMap, lem:gr_transition_pre_unit, lem:gr_transitionPreMap_minorDet}
1737	  \leanok
1738	  By \cref{lem:gr_transitionPreMap_minorDet} (taking the third subset \(K = I\)),
1739	  \(\tilde\theta_{I,J}(P^J_I)\) is the determinant of the \(I\)-minor of the image
1740	  matrix \(M = (X^I_J)^{-1} X^I\), which by
1741	  \cref{lem:gr_universalMatrix_map_transitionPreMap} equals
1742	  \(\det\bigl((X^I_J)^{-1} X^I_I\bigr) = \det\bigl((X^I_J)^{-1}\bigr)\). Hence
1743	  \(\tilde\theta_{I,J}(P^J_I) = \det(X^I_J)^{-1}\), and multiplying by \(P^I_J =
1744	  \det(X^I_J)\) gives \(\det(X^I_J)^{-1} \cdot \det(X^I_J) = 1\) by the
1745	  localisation-inverse cancellation for the unit \(\det(X^I_J)\)
1746	  (\cref{lem:gr_transition_pre_unit}).
1747	\end{proof}
