1749	\begin{definition}
1750	
1751	\leanok
1752	[Restricted-diagonal comorphism \(\delta_{I,J}\)]
1753	  \label{def:gr_diagonalRingMap}
1754	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap}
1755	  \uses{def:gr_transition_pre}
1756	  The \emph{restricted-diagonal comorphism} on the patch \(U^I \times_{\mathbb{Z}}
1757	  U^J\) is the \(\mathbb{Z}\)-algebra homomorphism
1758	  \[
1759	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1760	    \longrightarrow R^I_J,
1761	    \qquad
1762	    X^I \otimes 1 \mapsto X^I, \quad
1763	    1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1764	  \]
1765	  whose surjectivity is the content of separatedness; this is the \(\delta_{I,J}\)
1766	  of \cref{lem:gr_separated}.
1767	\end{definition}
1768	\begin{proof}
1769	  \uses{def:gr_transition_pre}
1770	  \leanok
1771	  Construct \(\delta_{I,J}\) as the tensor-product lift of the two commuting
1772	  factors: the structure map \(\mathbb{Z}[X^I] = R^I \to R^I_J\) on the left
1773	  factor, and the pre-localisation transition hom \(\tilde\theta_{I,J}\)
1774	  (\cref{def:gr_transition_pre}) on the right factor. Since both land in the
1775	  commutative ring \(R^I_J\), the universal property of the tensor product of
1776	  \(\mathbb{Z}\)-algebras yields a unique \(\mathbb{Z}\)-algebra homomorphism out
1777	  of \(\mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]\) restricting to these
1778	  factors; by construction its right component is \(\tilde\theta_{I,J}\).
1779	\end{proof}
1780	
1781	\begin{lemma}
1782	
1783	\leanok
1784	[Left component of \(\delta_{I,J}\)]
1785	  \label{lem:gr_diagonalRingMap_left}
1786	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap_left}
1787	  \uses{def:gr_diagonalRingMap}
1788	  For \(a \in \mathbb{Z}[X^I]\), the comorphism \(\delta_{I,J}\)
1789	  (\cref{def:gr_diagonalRingMap}) acts on the left factor by the structure map:
1790	  \[
1791	    \delta_{I,J}(a \otimes 1) \;=\; \mathrm{alg}_{R^I \to R^I_J}(a),
1792	  \]
1793	  the image of \(a\) under \(\mathbb{Z}[X^I] = R^I \to R^I_J\).
1794	\end{lemma}
1795	\begin{proof}
1796	  \uses{def:gr_diagonalRingMap}
1797	  \leanok
1798	  Immediate from the defining tensor-product lift of
1799	  \cref{def:gr_diagonalRingMap}: the value on a left elementary tensor \(a \otimes
1800	  1\) is the left factor evaluated at \(a\), i.e.\ the structure map.
1801	\end{proof}
1802	
1803	\begin{lemma}
1804	
1805	\leanok
1806	[Right component of \(\delta_{I,J}\)]
1807	  \label{lem:gr_diagonalRingMap_right}
1808	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap_right}
1809	  \uses{def:gr_diagonalRingMap}
1810	  For \(b \in \mathbb{Z}[X^J]\), the comorphism \(\delta_{I,J}\)
1811	  (\cref{def:gr_diagonalRingMap}) acts on the right factor by the pre-localisation
1812	  transition hom:
1813	  \[
1814	    \delta_{I,J}(1 \otimes b) \;=\; \tilde\theta_{I,J}(b)
1815	  \]
1816	  (\cref{def:gr_transition_pre}).
1817	\end{lemma}
1818	\begin{proof}
1819	  \uses{def:gr_diagonalRingMap}
1820	  \leanok
1821	  Immediate from the defining tensor-product lift of
1822	  \cref{def:gr_diagonalRingMap}: the value on a right elementary tensor \(1 \otimes
1823	  b\) is the right factor \(\tilde\theta_{I,J}\) evaluated at \(b\).
1824	\end{proof}
1825	
1826	\begin{lemma}
1827	
1828	\leanok
1829	[The restricted-diagonal comorphism is surjective]
1830	  \label{lem:gr_diagonalRingMap_surjective}
1831	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap_surjective}
1832	  \uses{lem:gr_diagonalRingMap_left, lem:gr_diagonalRingMap_right, lem:gr_transitionPreMap_minorDet_swap_mul}
1833	  The comorphism \(\delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}}
1834	  \mathbb{Z}[X^J] \to R^I_J\) (\cref{def:gr_diagonalRingMap}) is surjective.
1835	\end{lemma}
1836	\begin{proof}
1837	  \uses{lem:gr_diagonalRingMap_left, lem:gr_diagonalRingMap_right, lem:gr_transitionPreMap_minorDet_swap_mul}
1838	  \leanok
1839	  Let \(z \in R^I_J\). Since \(R^I_J = \mathbb{Z}[X^I, 1/P^I_J]\) is the
1840	  localisation of \(R^I = \mathbb{Z}[X^I]\) away from \(P^I_J\), surjectivity of
1841	  the localisation map provides \(a \in R^I\) and \(n \in \mathbb{N}\) with
1842	  \[
1843	    z \cdot (P^I_J)^n \;=\; \mathrm{alg}_{R^I \to R^I_J}(a).
1844	  \]
1845	  Consider the witness \(a \otimes (P^J_I)^n \in \mathbb{Z}[X^I]
1846	  \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]\). Using multiplicativity together with
1847	  \cref{lem:gr_diagonalRingMap_left} and \cref{lem:gr_diagonalRingMap_right},
1848	  \[
1849	    \delta_{I,J}\bigl(a \otimes (P^J_I)^n\bigr)
1850	      = \mathrm{alg}_{R^I \to R^I_J}(a) \cdot \tilde\theta_{I,J}(P^J_I)^n
1851	      = z \cdot (P^I_J)^n \cdot \tilde\theta_{I,J}(P^J_I)^n
1852	      = z \cdot \bigl(P^I_J \cdot \tilde\theta_{I,J}(P^J_I)\bigr)^n
1853	      = z,
1854	  \]
1855	  where the last equality uses \(P^I_J \cdot \tilde\theta_{I,J}(P^J_I) = 1\) from
1856	  \cref{lem:gr_transitionPreMap_minorDet_swap_mul}. Hence \(z\) lies in the image
1857	  of \(\delta_{I,J}\), so \(\delta_{I,J}\) is surjective.
1858	\end{proof}
1859	
1860	\begin{definition}
1861	
1862	\leanok
1863	[Source pullback iso \(e_2\) for the diagonal computation]
1864	  \label{def:gr_pullbackιIso}
1865	  \lean{AlgebraicGeometry.Grassmannian.pullbackιIso}
1866	  \uses{def:gr_glued_scheme, def:gr_chart_overlap}
1867	  The \emph{source pullback iso} \(e_2\) identifies the categorical fibre product
1868	  of two chart inclusions of the glued scheme (\cref{def:gr_glued_scheme}) with
1869	  the overlap chart:
1870	  \[
1871	    e_2 : \mathrm{pullback}\,(\iota_i)\,(\iota_j) \;\xrightarrow{\;\sim\;}\;
1872	    U^I \cap U^J \;=\; \texttt{chartOverlap}\,(d,r,i,j)
1873	  \]
1874	  (\cref{def:gr_chart_overlap}), where \(\iota_i, \iota_j\) are the open
1875	  immersions of the charts \(U^I, U^J\) into \(\mathrm{Gr}(r,d)\).
1876	\end{definition}
1877	\begin{proof}
1878	  \uses{def:gr_glued_scheme, def:gr_chart_overlap}
1879	  \leanok
1880	  The glue data of \cref{def:gr_glued_scheme} supplies, for each pair \((i,j)\), a
1881	  pullback cone over \(\iota_i, \iota_j\) with apex the overlap chart \(U^I \cap
1882	  U^J\), and this cone is a limit cone. Comparing it with the categorical
1883	  pullback limit cone via the uniqueness-up-to-isomorphism of limit cone points
1884	  yields the desired isomorphism \(e_2\).
1885	\end{proof}
1886	
1887	\begin{definition}
1888	[Structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)]
1889	  \label{def:gr_to_specZ}
1890	  \lean{AlgebraicGeometry.Grassmannian.toSpecZ}
1891	  \uses{def:gr_glued_scheme}
1892	  The \emph{structure morphism} of the glued Grassmannian scheme
1893	  (\cref{def:gr_glued_scheme}) is the canonical map
1894	  \[
1895	    \mathrm{Gr}(r,d) \longrightarrow \Spec \mathbb{Z} .
1896	  \]
1897	  As \(\mathrm{Gr}(r,d)\) lives in the category of schemes over \(\mathbb{Z}\), in
1898	  which \(\Spec \mathbb{Z}\) is the terminal object, this morphism is the unique
1899	  map to that terminal object. It is the genuine base over which separatedness and
1900	  properness of the Grassmannian are formulated.
1901	\end{definition}
1902	
1903	\begin{lemma}
1904	[The chart map composes to the affine structure map]
1905	  \label{lem:gr_ι_toSpecZ}
1906	  \lean{AlgebraicGeometry.Grassmannian.ι_toSpecZ}
1907	  \uses{def:gr_to_specZ, def:gr_glued_scheme}
1908	  For each index \(i = (I, \cdot)\), the chart immersion \(\iota_i : U^I \to
1909	  \mathrm{Gr}(r,d)\) of the glue datum (\cref{def:gr_glued_scheme}) composed with
1910	  the structure morphism (\cref{def:gr_to_specZ}) is the affine structure map of
1911	  the chart:
1912	  \[
1913	    \iota_i \circ (\mathrm{Gr}(r,d) \to \Spec \mathbb{Z})
1914	      \;=\; \Spec(\mathbb{Z} \to R^I),
1915	  \]
1916	  the \(\Spec\) of the canonical ring map \(\mathbb{Z} \to R^I =
1917	  \mathbb{Z}[X^I]\).
1918	\end{lemma}
1919	\begin{proof}
1920	  \uses{def:gr_to_specZ, def:gr_glued_scheme}
1921	  Both sides are morphisms from \(U^I\) into the terminal object \(\Spec
1922	  \mathbb{Z}\), hence they coincide by uniqueness of the terminal map.
1923	\end{proof}
1924	
1925	\begin{lemma}
1926	[First projection leg of the source pullback iso]
1927	  \label{lem:gr_pullbackιIso_inv_fst}
1928	  \lean{AlgebraicGeometry.Grassmannian.pullbackιIso_inv_fst}
1929	  \uses{def:gr_pullbackιIso, def:gr_chart_incl}
1930	  The inverse of the source pullback iso \(e_2\) (\cref{def:gr_pullbackιIso}),
1931	  followed by the first projection of the fibre product, is the chart inclusion:
1932	  \[
1933	    e_2^{-1} \circ \mathrm{pr}_1 \;=\; \iota^I_J : U^I_J \to U^I ,
1934	  \]
1935	  the \(\mathrm{pr}_1\) leg being the projection of
1936	  \(\mathrm{pullback}\,(\iota_i)\,(\iota_j)\) onto \(U^I\)
1937	  (\cref{def:gr_chart_incl}).
1938	\end{lemma}
1939	\begin{proof}
1940	  \uses{def:gr_pullbackιIso, def:gr_chart_incl}
1941	  By construction \(e_2\) is the comparison isomorphism between the categorical
1942	  pullback limit cone and the glue-datum pullback cone over \(\iota_i, \iota_j\).
1943	  The compatibility of a limit-cone comparison isomorphism with the cone legs
1944	  (uniqueness-up-to-isomorphism of limit cone points, applied to the left leg of
1945	  the cospan) identifies \(e_2^{-1} \circ \mathrm{pr}_1\) with the corresponding
1946	  leg of the glue-datum cone, which is the chart inclusion \(\iota^I_J\).
1947	\end{proof}
1948	
1949	\begin{lemma}
1950	[Second projection leg of the source pullback iso]
1951	  \label{lem:gr_pullbackιIso_inv_snd}
1952	  \lean{AlgebraicGeometry.Grassmannian.pullbackιIso_inv_snd}
1953	  \uses{def:gr_pullbackιIso, def:gr_chart_incl, def:gr_chart_transition}
1954	  The inverse of the source pullback iso \(e_2\) (\cref{def:gr_pullbackιIso}),
1955	  followed by the second projection of the fibre product, is the scheme-level
1956	  transition composed with the opposite chart inclusion:
1957	  \[
1958	    e_2^{-1} \circ \mathrm{pr}_2
1959	      \;=\; t_{I,J} \circ \iota^J_I : U^I_J \to U^J_I \to U^J ,
1960	  \]
1961	  the transition \(t_{I,J}\) of \cref{def:gr_chart_transition} followed by the
1962	  chart inclusion of \cref{def:gr_chart_incl}.
1963	\end{lemma}
1964	\begin{proof}
1965	  \uses{def:gr_pullbackιIso, def:gr_chart_incl, def:gr_chart_transition}
1966	  As in \cref{lem:gr_pullbackιIso_inv_fst}, but using the right leg of the cospan:
1967	  the glue-datum pullback cone's second leg is the composite \(t \circ f\) of the
1968	  glue datum (transition followed by inclusion), so the comparison isomorphism
1969	  identifies \(e_2^{-1} \circ \mathrm{pr}_2\) with \(t_{I,J} \circ \iota^J_I\).
1970	\end{proof}
1971	
1972	\begin{lemma}
1973	[The transition-then-inclusion composite is affine]
1974	  \label{lem:gr_chartTransition_comp_chartIncl}
1975	  \lean{AlgebraicGeometry.Grassmannian.chartTransition_comp_chartIncl}
1976	  \uses{def:gr_chart_transition, def:gr_chart_incl, def:gr_transition_pre}
1977	  The composite of the scheme-level transition
1978	  (\cref{def:gr_chart_transition}) with the opposite chart inclusion
1979	  (\cref{def:gr_chart_incl}) is the \(\Spec\) of the pre-localisation transition
1980	  homomorphism \(\tilde\theta_{I,J} : R^J \to R^I[1/P^I_J]\)
1981	  (\cref{def:gr_transition_pre}):
1982	  \[
1983	    t_{I,J} \circ \iota^J_I \;=\; \Spec \tilde\theta_{I,J} :
1984	      U^I_J \to U^J .
1985	  \]
1986	\end{lemma}
1987	\begin{proof}
1988	  \uses{def:gr_chart_transition, def:gr_chart_incl, def:gr_transition_pre}
1989	  Unfolding the two scheme maps, the composite is \(\Spec\) of the ring map
1990	  obtained by precomposing the localised transition \(\theta_{I,J} :
1991	  R^J[1/P^J_I] \to R^I[1/P^I_J]\) with the localisation \(R^J \to R^J[1/P^J_I]\).
1992	  By the universal property of the away-localisation (the lift commutes with the
1993	  localisation map), this composite ring map is exactly the pre-localisation
1994	  transition \(\tilde\theta_{I,J}\); applying \(\Spec\) and the contravariance of
1995	  composition gives the claim.
1996	\end{proof}
1997	
1998	\begin{lemma}
1999	[The structure morphism is separated (morphism form)]
2000	  \label{lem:gr_separated_toSpecZ}
2001	  \lean{AlgebraicGeometry.Grassmannian.isSeparatedToSpecZ}
2002	  \uses{def:gr_to_specZ, def:gr_glued_scheme, def:gr_pullbackιIso,
2003	    def:gr_diagonalRingMap, lem:gr_diagonalRingMap_surjective,
2004	    lem:gr_ι_toSpecZ, lem:gr_pullbackιIso_inv_fst,
2005	    lem:gr_pullbackιIso_inv_snd, lem:gr_chartTransition_comp_chartIncl}
2006	  The structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
2007	  (\cref{def:gr_to_specZ}) is separated: its diagonal is a closed immersion.
2008	\end{lemma}
2009	\begin{proof}
2010	  \uses{def:gr_to_specZ, def:gr_glued_scheme, def:gr_pullbackιIso,
2011	    def:gr_diagonalRingMap, lem:gr_diagonalRingMap_surjective,
2012	    lem:gr_ι_toSpecZ, lem:gr_pullbackιIso_inv_fst,
2013	    lem:gr_pullbackιIso_inv_snd, lem:gr_chartTransition_comp_chartIncl}
2014	  Separatedness is local on the target of the diagonal, so it may be checked on
2015	  the cover of \(\mathrm{Gr}(r,d) \times_{\mathbb{Z}} \mathrm{Gr}(r,d)\) by the
2016	  patch products \(U^I \times_{\mathbb{Z}} U^J\) (the left--right product of the
2017	  chart open cover with itself). Fix a patch \((i,j)\). On it the restricted
2018	  diagonal is identified, via the source pullback iso \(e_2\)
2019	  (\cref{def:gr_pullbackιIso}) — whose two legs are computed in
2020	  \cref{lem:gr_pullbackιIso_inv_fst} and \cref{lem:gr_pullbackιIso_inv_snd},
2021	  using \cref{lem:gr_ι_toSpecZ} and \cref{lem:gr_chartTransition_comp_chartIncl}
2022	  to read off the affine comorphisms — and the target affine iso (the pullback of
2023	  two affine schemes is the \(\Spec\) of the tensor product), with the affine
2024	  morphism \(\Spec \delta_{I,J}\), where \(\delta_{I,J}\) is the
2025	  restricted-diagonal comorphism of \cref{def:gr_diagonalRingMap}. Since
2026	  \(\delta_{I,J}\) is surjective (\cref{lem:gr_diagonalRingMap_surjective}), the
2027	  morphism \(\Spec \delta_{I,J}\) is a closed immersion. As every patch of the
2028	  diagonal is a closed immersion, the diagonal is a closed immersion and the
2029	  structure morphism is separated.
2030	\end{proof}
2031	
2032	\begin{lemma}
2033	
2034	\leanok
2035	[\(\mathrm{Gr}(r,d)\) is separated over \(\mathbb{Z}\)]
2036	  \label{lem:gr_separated}
2037	  \lean{AlgebraicGeometry.Grassmannian.isSeparated}
